data.content:
Here's how to test `DataFetcher` with modern MSTest 3.x, properly handling timeouts and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello world"),
        });
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.InternalServerError,
        });
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange
        var handler = new SlowHttpMessageHandler(delay: TimeSpan.FromSeconds(30));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // test fails if FetchAsync doesn't respect cancellation
    public async Task FetchAsync_TimeoutViaTestContext_IsCancelledCooperatively()
    {
        // Arrange — handler delays longer than the [Timeout]
        var handler = new SlowHttpMessageHandler(delay: TimeSpan.FromSeconds(60));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert — TestContext.CancellationToken fires when [Timeout] expires
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    // --- Test doubles ---

    private sealed class FakeHttpMessageHandler(HttpResponseMessage response) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(response);
        }
    }

    private sealed class SlowHttpMessageHandler(TimeSpan delay) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(delay, cancellationToken); // respects cancellation
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---------|-----|
| `TestContext` via constructor injection | Access `CancellationToken` for cooperative timeout |
| `[Timeout(ms)]` + `_testContext.CancellationToken` | MSTest cancels the token when timeout expires — your code must pass it through |
| `Assert.ThrowsExactlyAsync<T>` | Asserts the exact exception type (not `[ExpectedException]`) |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over HTTP behavior |
| `sealed` test class | Performance best practice in MSTest 3.x+ |

The critical insight: `[Timeout]` alone won't stop a hung async call — you **must** flow `TestContext.CancellationToken` into the code under test so it can cancel cooperatively.
